class Vehicle {}
class Car   extends Vehicle { public String honk() { return "Beep!"; } }
class Truck extends Vehicle { public String honk() { return "Honk!"; } }

public class Main {
    public static void honkAll(Vehicle[] vehicles) {
        for (Vehicle v : vehicles) {
            if      (v instanceof Car c)   System.out.println(c.honk());
            else if (v instanceof Truck t) System.out.println(t.honk());
        }
    }

    public static void main(String[] args) {
        honkAll(new Vehicle[]{new Car(), new Truck(), new Car()});
    }
}
